import React from "react";
import { InputTextarea, type InputTextareaProps } from "primereact/inputtextarea";
import type { IKitsInputTextarea } from "@lmb-it/kitsconcerto-types";
import KitsContainer from "../../helpers/FormContainer";
import { useSeparator } from "../../../factory";
import { useFormInputController } from "../../helpers/useFormInputController";
import { useComponentDefaults, useResolvedStyle } from "../../../hooks";

const KitsInputTextarea = ({ ref, ...rawProps }: IKitsInputTextarea) => {
    const {mergedProps: props, themeStyle, elementStyles} = useComponentDefaults('Textarea', rawProps);
    const resolvedThemeStyle = useResolvedStyle(themeStyle);
    const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});
    const {
        id,
        autoResize,
        rows,
        cols,
        label,
        onChange,
        value,
        defaultValue,
        keyFilter,
        errors,
        hideError,
        invalid,
        isFloatedLabel,
        isChecked,
        disabled,
        helperText,
        inputSize,
        containerStyle,
        localProps,
        attached,
        ...rest
    } = props as IKitsInputTextarea & { localProps?: InputTextareaProps };

    // 🔑 unified controlled / uncontrolled logic
    const { value: displayValue, emitChange } =
        useFormInputController<string>({
            value,
            defaultValue,
            onChange,
        });

    const { nativeProps } = useSeparator<InputTextareaProps>({
        ...(rest as any),
        ...(localProps as any),
    });

    const Element = <InputTextarea
        ref={ref as any}
        value={displayValue ?? ""}
        onChange={(e) => emitChange(e.target.value)}
        keyfilter={keyFilter as any}
        disabled={disabled}
        autoResize={autoResize}
        rows={rows}
        cols={cols}
        className={`w-full ${nativeProps.className ?? ""}`}
        style={{ borderRadius: 0, border:'none', ...(resolvedRootStyle || resolvedThemeStyle) }}
        {...nativeProps}
    />;

    if (attached) {
        return Element;
    }

    return (
        <KitsContainer
            id={id}
            helperText={helperText}
            isFloatedLabel={isFloatedLabel}
            errors={errors}
            invalid={invalid}
            label={label}
            hideError={hideError}
            required={props.required}
            disabled={disabled}
            inputSize={inputSize}
            containerStyle={containerStyle}
            elementStyles={elementStyles}
        >
            {Element}
        </KitsContainer>
    );
};

export default KitsInputTextarea;
